// src/app/dashboard/page.tsx
import React from "react";
import { redirect } from "next/navigation";
import UploadZone from "@/app/components/UploadZone"; // optional - see stub below
import ResumeList from "@/app/dashboard/ResumeList";
import { getResumes } from "@/app/lib/data";
import { createClient } from "@/app/lib/supabase/server";

export default async function DashboardPage() {
  // Protect route
  const supabase = await createClient();
  const { data: userData } = await supabase.auth.getUser();
  const user = userData.user;

  if (!user) {
    // not logged in -> redirect to login
    redirect("/login");
  }

  // Fetch resumes
  const resumes = await getResumes();

  // (optional) console.log for debugging — will appear in server console
  console.log("Dashboard resumes:", resumes);

  return (
    <main className="min-h-screen bg-slate-50 p-8">
      <div className="max-w-5xl mx-auto space-y-10">
        {/* Header */}
        <div className="flex justify-between items-center">
          <h1 className="text-3xl font-bold text-slate-900">My Resumes</h1>
          <div className="text-sm text-slate-500">
            {user.email}
          </div>
        </div>

        {/* Upload Area */}
        <section className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm">
          <h2 className="text-xl font-semibold mb-6">New Scan</h2>
          <UploadZone />
        </section>

        {/* History List */}
        <section>
          <h2 className="text-xl font-semibold mb-6">Recent Scans</h2>
          <ResumeList resumes={resumes} />
        </section>
      </div>
    </main>
  );
}
